import{_ as a,c as n,g as l,o as p}from"./chunks/framework.BHLsqBdN.js";const F=JSON.parse('{"title":"Shell","description":"","frontmatter":{},"headers":[{"level":1,"title":"Shell","slug":"shell","link":"#shell","children":[{"level":2,"title":"Startup files","slug":"startup-files","link":"#startup-files","children":[]},{"level":2,"title":"Interactive and non-interactive","slug":"interactive-and-non-interactive","link":"#interactive-and-non-interactive","children":[]}]}],"relativePath":"unready/linux/shell.md","filePath":"unready/linux/shell.md"}'),e={name:"unready/linux/shell.md"};function o(t,s,c,r,i,y){return p(),n("div",null,[...s[0]||(s[0]=[l(`<h1 id="shell" tabindex="-1">Shell <a class="header-anchor" href="#shell" aria-label="Permalink to &quot;Shell&quot;">​</a></h1><h2 id="startup-files" tabindex="-1">Startup files <a class="header-anchor" href="#startup-files" aria-label="Permalink to &quot;Startup files&quot;">​</a></h2><p>如果以普通用户的角度出发，我想我们最先关心的应该是 shell 的启动路径了，那么以 bash 为例，顺序如下：</p><p>/etc/profile -&gt; $HOME/.bash_profile, $HOME/.bash_login, $HOME/.profile -&gt; $HOME/.bash_logout</p><p>注：$HOME/.bash_profile, $HOME/.bash_login 和 $HOME/.profile 这三个文件并非覆盖式加载，而是按顺序访问，若访问到该文件有效，则后面的文件不会被加载。即如果 .bash_profile 存在，则只加载这个文件，后面的两个将被忽视。</p><ul><li>/etc/profile</li></ul><p>登录时第一个被加载的文件，一般避免修改它，以我的 Archlinux 默认生成的为例并加注释解读：</p><div class="language-bash"><button title="复制代码" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#676E95;font-style:italic;"># /etc/profile</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># 提供快捷增加路径的方法，使得之后不用写 export PATH=&quot;$PATH:$HOME/mypath&quot; 并检查是否重复</span></span>
<span class="line"><span style="color:#82AAFF;">append_path</span><span style="color:#89DDFF;"> ()</span><span style="color:#89DDFF;"> {</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">    case</span><span style="color:#89DDFF;"> &quot;</span><span style="color:#C3E88D;">:</span><span style="color:#BABED8;">$PATH</span><span style="color:#C3E88D;">:</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;font-style:italic;"> in</span></span>
<span class="line"><span style="color:#89DDFF;">        *</span><span style="color:#C3E88D;">:</span><span style="color:#89DDFF;">&quot;</span><span style="color:#BABED8;font-style:italic;">$1</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">:</span><span style="color:#89DDFF;">*</span><span style="color:#89DDFF;">)</span></span>
<span class="line"><span style="color:#89DDFF;">            ;;</span></span>
<span class="line"><span style="color:#89DDFF;">        *)</span></span>
<span class="line"><span style="color:#BABED8;">            PATH</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;\${</span><span style="color:#BABED8;">PATH</span><span style="color:#89DDFF;">:</span><span style="color:#C3E88D;">+</span><span style="color:#BABED8;">$PATH</span><span style="color:#89DDFF;">:}</span><span style="color:#BABED8;font-style:italic;">$1</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">    esac</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># 默认路径</span></span>
<span class="line"><span style="color:#FFCB6B;">append_path</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">/usr/local/sbin</span><span style="color:#89DDFF;">&#39;</span></span>
<span class="line"><span style="color:#FFCB6B;">append_path</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">/usr/local/bin</span><span style="color:#89DDFF;">&#39;</span></span>
<span class="line"><span style="color:#FFCB6B;">append_path</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">/usr/bin</span><span style="color:#89DDFF;">&#39;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">export</span><span style="color:#BABED8;"> PATH</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># 加载 /etc/profile.d 下的所有脚本，软件在这里放置自己特有的启动文件，bash会自动依次加载</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">if</span><span style="color:#82AAFF;"> test</span><span style="color:#C3E88D;"> -d</span><span style="color:#C3E88D;"> /etc/profile.d/</span><span style="color:#89DDFF;">;</span><span style="color:#89DDFF;font-style:italic;"> then</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">	for</span><span style="color:#BABED8;"> profile </span><span style="color:#89DDFF;font-style:italic;">in</span><span style="color:#C3E88D;"> /etc/profile.d/*.sh</span><span style="color:#89DDFF;">;</span><span style="color:#89DDFF;font-style:italic;"> do</span></span>
<span class="line"><span style="color:#82AAFF;">		test</span><span style="color:#C3E88D;"> -r</span><span style="color:#89DDFF;"> &quot;</span><span style="color:#BABED8;">$profile</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;"> &amp;&amp;</span><span style="color:#82AAFF;"> .</span><span style="color:#89DDFF;"> &quot;</span><span style="color:#BABED8;">$profile</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">	done</span></span>
<span class="line"><span style="color:#82AAFF;">	unset</span><span style="color:#C3E88D;"> profile</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">fi</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># unset GLOBSORT, before anything else is sourced</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># This variable will be part of bash =&gt; 5.3</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># The rationale is that the user should always be able </span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># to expect that the snippets be processed in a deterministic order.</span></span>
<span class="line"><span style="color:#82AAFF;">unset</span><span style="color:#C3E88D;"> -v</span><span style="color:#C3E88D;"> GLOBSORT</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># 在这里注销了添加 PATH 的函数，因此这个函数只是给 /etc/profile.d 用的，我们之后写的脚本用不了</span></span>
<span class="line"><span style="color:#82AAFF;">unset</span><span style="color:#C3E88D;"> -f</span><span style="color:#C3E88D;"> append_path</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># Source global bash config, when interactive but not posix or sh mode</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">if</span><span style="color:#82AAFF;"> test</span><span style="color:#89DDFF;"> &quot;</span><span style="color:#BABED8;">$BASH</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;"> &amp;&amp;</span><span style="color:#BABED8;">\\</span></span>
<span class="line"><span style="color:#82AAFF;">   test</span><span style="color:#89DDFF;"> &quot;</span><span style="color:#BABED8;">$PS1</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;"> &amp;&amp;</span><span style="color:#BABED8;">\\</span></span>
<span class="line"><span style="color:#82AAFF;">   test</span><span style="color:#C3E88D;"> -z</span><span style="color:#89DDFF;"> &quot;</span><span style="color:#BABED8;">$POSIXLY_CORRECT</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;"> &amp;&amp;</span><span style="color:#BABED8;">\\</span></span>
<span class="line"><span style="color:#82AAFF;">   test</span><span style="color:#89DDFF;"> &quot;</span><span style="color:#BABED8;font-style:italic;">\${0</span><span style="color:#89DDFF;">#</span><span style="color:#BABED8;">-</span><span style="color:#BABED8;font-style:italic;">}</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;"> !=</span><span style="color:#C3E88D;"> sh</span><span style="color:#89DDFF;"> &amp;&amp;</span><span style="color:#BABED8;">\\</span></span>
<span class="line"><span style="color:#82AAFF;">   test</span><span style="color:#C3E88D;"> -r</span><span style="color:#C3E88D;"> /etc/bash.bashrc</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">then</span></span>
<span class="line"><span style="color:#82AAFF;">	.</span><span style="color:#C3E88D;"> /etc/bash.bashrc</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">fi</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># Termcap is outdated, old, and crusty, kill it.</span></span>
<span class="line"><span style="color:#82AAFF;">unset</span><span style="color:#C3E88D;"> TERMCAP</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># Man is much better than us at figuring this out</span></span>
<span class="line"><span style="color:#82AAFF;">unset</span><span style="color:#C3E88D;"> MANPATH</span></span></code></pre></div><ul><li>$HOME/.bash_profile, $HOME/.bash_login, $HOME/.profile</li></ul><p>用户级的bash启动配置，使用 --noprofile 参数可以不启用它们</p><p>通常使用 ~/.bash_profile 就够了，并且包含以下内容：</p><div class="language-bash"><button title="复制代码" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">if</span><span style="color:#89DDFF;"> [</span><span style="color:#89DDFF;"> -f</span><span style="color:#89DDFF;"> ~</span><span style="color:#BABED8;">/.bashrc </span><span style="color:#89DDFF;">];</span><span style="color:#89DDFF;font-style:italic;"> then</span><span style="color:#82AAFF;"> .</span><span style="color:#C3E88D;"> ~/.bashrc</span><span style="color:#89DDFF;">;</span><span style="color:#89DDFF;font-style:italic;"> fi</span></span></code></pre></div><p>这段脚本会检查是否有 ~/.bashrc 如果有就加载，没有就跳过，防止报错</p><p>因此我们实际上手动配置的是 ~/.bashrc 这个文件，比如放置我们想要的别名：</p><div class="language-bash"><button title="复制代码" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">alias</span><span style="color:#BABED8;"> ls</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">ls --color=auto</span><span style="color:#89DDFF;">&#39;</span></span>
<span class="line"><span style="color:#C792EA;">alias</span><span style="color:#BABED8;"> grep</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">grep --color=auto</span><span style="color:#89DDFF;">&#39;</span></span></code></pre></div><h2 id="interactive-and-non-interactive" tabindex="-1">Interactive and non-interactive <a class="header-anchor" href="#interactive-and-non-interactive" aria-label="Permalink to &quot;Interactive and non-interactive&quot;">​</a></h2><p>其次我们关心的就是 shell 以怎样的方式运行</p>`,17)])])}const h=a(e,[["render",o]]);export{F as __pageData,h as default};
